"use client";
import React, { useState, useEffect } from 'react';
import { subscribeToCollection, deleteDocument, createDocument } from '../../../lib/adminDb';
import { MOCK_PRODUCTS } from '../../../constants';

interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  stock: number;
  status: string;
  images?: string[];
}

interface Category {
  id: string;
  name: string;
}

export default function AdminProducts() {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  
  // Add Product State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newProdName, setNewProdName] = useState('');
  const [newProdCategory, setNewProdCategory] = useState('');
  const [newProdPrice, setNewProdPrice] = useState<number | string>('');
  const [newProdStock, setNewProdStock] = useState<number | string>('');

  useEffect(() => {
    setIsLoading(true);
    const unsubCat = subscribeToCollection('categories', (data) => {
      setCategories(data as Category[]);
    });

    const unsubProd = subscribeToCollection('products', (data) => {
      const dbProducts = data as Product[];
      
      // Combine with mock products
      const existingIds = new Set(dbProducts.map(p => String(p.id)));
      const missingMockProducts = MOCK_PRODUCTS.filter((p: any) => !existingIds.has(String(p.id))).map((p: any) => ({
          id: String(p.id),
          name: p.name,
          category: p.category || 'Wellness',
          price: p.price || 0,
          stock: p.stock || 100, // mock stock
          status: 'Published', // mock
          images: [p.image]
      }));
      setProducts([...dbProducts, ...missingMockProducts]);
      setIsLoading(false);
    });

    return () => {
      unsubCat();
      unsubProd();
    };
  }, []);

  const handleCreateProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProdName || !newProdCategory) return;
    try {
        await createDocument('products', {
            name: newProdName,
            category: newProdCategory,
            price: Number(newProdPrice),
            stock: Number(newProdStock),
            status: 'Published'
        });
        setIsModalOpen(false);
        setNewProdName('');
        setNewProdCategory('');
        setNewProdPrice('');
        setNewProdStock('');
    } catch(err) {
        console.error(err);
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete ${name}? This action cannot be undone.`)) {
      try {
        await deleteDocument('products', id);
        setProducts(products.filter(p => p.id !== id));
      } catch (err) {
        console.error("Error deleting product", err);
        alert("Failed to delete product.");
      }
    }
  };

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name ? p.name.toLowerCase().includes(search.toLowerCase()) : false;
    const matchesCategory = categoryFilter ? p.category === categoryFilter : true;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h1 className="text-3xl font-bold text-slate-800 tracking-tight">Product Management</h1>
        <button onClick={() => setIsModalOpen(true)} className="bg-forest text-white px-6 py-2.5 rounded-md font-bold hover:bg-forest/90 transition-colors shadow-sm flex items-center gap-2">
          <span className="material-symbols-outlined text-[20px]">add</span>
          Add New Product
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col sm:flex-row gap-4">
        <div className="flex-1 relative">
          <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">search</span>
          <input 
            type="text" 
            placeholder="Search products by name..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-md focus:outline-none focus:border-forest"
          />
        </div>
        <select 
          value={categoryFilter}
          onChange={(e) => setCategoryFilter(e.target.value)}
          className="w-full sm:w-64 border border-slate-300 rounded-md px-4 py-2 focus:outline-none focus:border-forest bg-white"
        >
          <option value="">All Categories</option>
          {categories.map(c => (
            <option key={c.id} value={c.name}>{c.name}</option>
          ))}
          {categories.length === 0 && <option value="Ayurvedic Medicines">Ayurvedic Medicines (Mock)</option>}
        </select>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider border-b border-slate-200">
                <th className="p-4 font-bold">Image</th>
                <th className="p-4 font-bold">Name</th>
                <th className="p-4 font-bold">Category</th>
                <th className="p-4 font-bold">Price</th>
                <th className="p-4 font-bold">Stock</th>
                <th className="p-4 font-bold">Status</th>
                <th className="p-4 font-bold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="text-sm divide-y divide-slate-100 text-slate-700">
              {isLoading ? (
                <tr>
                  <td colSpan={7} className="p-12 text-center text-slate-500">
                    <div className="flex flex-col items-center justify-center gap-3">
                      <div className="w-8 h-8 border-4 border-forest border-t-transparent rounded-full animate-spin"></div>
                      <p>Loading products...</p>
                    </div>
                  </td>
                </tr>
              ) : filteredProducts.length === 0 ? (
                <tr>
                  <td colSpan={7} className="p-12 text-center text-slate-500">
                    <div className="flex flex-col items-center justify-center gap-3">
                      <span className="material-symbols-outlined text-4xl">inventory_2</span>
                      <p>No products found.</p>
                    </div>
                  </td>
                </tr>
              ) : (
                filteredProducts.map((product) => (
                  <tr key={product.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4">
                      <div className="w-12 h-12 bg-slate-100 rounded border border-slate-200 overflow-hidden flex items-center justify-center">
                        {product.images && product.images.length > 0 ? (
                          <img src={product.images[0]} alt={product.name} className="w-full h-full object-cover" />
                        ) : (
                          <span className="material-symbols-outlined text-slate-400">image</span>
                        )}
                      </div>
                    </td>
                    <td className="p-4 font-bold text-slate-900">{product.name}</td>
                    <td className="p-4">{product.category}</td>
                    <td className="p-4 font-medium text-slate-900">₹{Number(product.price).toLocaleString()}</td>
                    <td className="p-4">
                      <span className={Number(product.stock) < 10 ? 'text-red-600 font-bold' : ''}>
                        {product.stock}
                      </span>
                    </td>
                    <td className="p-4">
                      <span className={`px-2.5 py-1 text-[11px] uppercase tracking-wider font-bold rounded-md ${
                        product.status === 'Published' ? 'bg-green-100 text-green-800' : 'bg-slate-100 text-slate-800'
                      }`}>
                        {product.status || 'Draft'}
                      </span>
                    </td>
                    <td className="p-4 text-right space-x-2 whitespace-nowrap">
                       <button className="text-blue-600 hover:text-blue-800 hover:bg-blue-50 px-2 py-1 rounded transition-colors" title="Edit">
                         <span className="material-symbols-outlined text-[18px]">edit</span>
                       </button>
                       <button onClick={() => handleDelete(product.id, product.name)} className="text-red-600 hover:text-red-800 hover:bg-red-50 px-2 py-1 rounded transition-colors" title="Delete">
                         <span className="material-symbols-outlined text-[18px]">delete</span>
                       </button>
                       <a href={`/products/${product.id}`} target="_blank" rel="noopener noreferrer" className="inline-block text-slate-500 hover:text-slate-800 hover:bg-slate-100 px-2 py-1 rounded transition-colors" title="View on Site">
                         <span className="material-symbols-outlined text-[18px]">visibility</span>
                       </a>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm px-4">
          <div className="absolute inset-0 cursor-pointer" onClick={() => setIsModalOpen(false)} />
          <div className="relative z-10 w-full max-w-lg bg-white p-8 rounded-xl shadow-2xl">
            <h2 className="text-2xl font-bold mb-6 text-slate-800">Add New Product</h2>
            <form onSubmit={handleCreateProduct} className="flex flex-col gap-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Product Name</label>
                <input type="text" value={newProdName} onChange={e => setNewProdName(e.target.value)} className="w-full border border-slate-300 rounded px-4 py-2.5 focus:outline-none focus:border-forest" required />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Category</label>
                <select value={newProdCategory} onChange={e => setNewProdCategory(e.target.value)} className="w-full border border-slate-300 rounded px-4 py-2.5 focus:outline-none focus:border-forest bg-white" required>
                  <option value="">Select Category</option>
                  {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">Price (₹)</label>
                  <input type="number" value={newProdPrice} onChange={e => setNewProdPrice(e.target.value)} className="w-full border border-slate-300 rounded px-4 py-2.5 focus:outline-none focus:border-forest" required min="0" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">Initial Stock</label>
                  <input type="number" value={newProdStock} onChange={e => setNewProdStock(e.target.value)} className="w-full border border-slate-300 rounded px-4 py-2.5 focus:outline-none focus:border-forest" required min="0" />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-2.5 text-slate-600 font-bold hover:bg-slate-100 rounded transition-colors">Cancel</button>
                <button type="submit" className="bg-forest text-white px-6 py-2.5 rounded font-bold hover:bg-forest/90 transition-colors">Save Product</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
